// // This module converts an 8-bit binary number to its equivalent Gray code representation. Upon receiving a reset signal, the output is initialized to one. On each positive clock edge, if not in reset, the module computes the Gray code by applying the formula for each bit, with the least significant bit (LSB) being copied directly from the binary input and each subsequent bit computed as the AND of adjacent bits from the binary input.
module top_module(
  input wire clk,
  input wire reset,
  input wire [7:0] bin,
  output reg [7:0] gray
);always @(posedge clk, posedge reset) begin
    if (reset) begin
      gray <= 8'b0;
    end else begin
      gray[7] <= bin[7];
      gray[6] <= bin[7] ^ bin[6];
      gray[5] <= bin[6] ^ bin[5];
      gray[4] <= bin[5] ^ bin[4];
      gray[3] <= bin[4] ^ bin[3];
      gray[2] <= bin[3] ^ bin[2];
      gray[1] <= bin[2] ^ bin[1];
      gray[0] <= bin[1] ^ bin[0];
    end
  end

endmodule
